"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[68774],{956874:e=>{e.exports=JSON.parse('{"tag":{"label":"plant","permalink":"/dst-api-webdocs/docs/tags/plant","allTagsPath":"/dst-api-webdocs/docs/tags","count":55,"items":[{"id":"game-scripts/prefabs/ancienttree_seed","title":"Ancienttree seed","description":"A deployable item that spawns a randomly generated ancient tree sapling when placed in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancienttree_seed"},{"id":"game-scripts/prefabs/ancienttrees","title":"Ancienttrees","description":"Manages the lifecycle, growth, and interaction of ancient trees and their saplings, including seed deployment, growth staging, fruit production, and stump conversion upon harvesting.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancienttrees"},{"id":"game-scripts/prefabs/bananabush","title":"Bananabush","description":"A plantable ground entity that grows through visual stages and yields cave bananas when picked, then regrows over time or resets after being dug up.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bananabush"},{"id":"game-scripts/prefabs/beeswax_spray","title":"Beeswax Spray","description":"A consumable item that applies wax to plants and trees, temporarily protecting them from harvest damage or decay.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beeswax_spray"},{"id":"game-scripts/prefabs/berrybush","title":"Berrybush","description":"Handles the lifecycle, regeneration, and loot spawning of berry bushes, including growth states, seasonal interactions, and special event behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/berrybush"},{"id":"game-scripts/components/bloomness","title":"Bloomness","description":"Manages the growth stage and bloom progression of a plant entity, including timer-based progression, fertilization effects, and rate calculation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/bloomness"},{"id":"game-scripts/prefabs/cactus","title":"Cactus","description":"Handles the behavior and interactions of cactus plants in the game world, including harvesting, thorn damage, seasonal flowering, and regrowth mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cactus"},{"id":"game-scripts/prefabs/cave_banana_tree","title":"Cave Banana Tree","description":"Manages the full lifecycle of a cave banana tree, including growth, harvesting, chopping, burning, and regrowth into stumps or burnt stumps.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cave_banana_tree"},{"id":"game-scripts/components/crop","title":"Crop","description":"Manages growth, maturation, fertilization, and harvesting logic for plant entities in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/crop"},{"id":"game-scripts/prefabs/eyeplant","title":"Eyeplant","description":"Manages the entity logic for the Eyeplant, a stationary hostile plant that targets and attacks enemies within range using combat, health, and locomotion components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/eyeplant"},{"id":"game-scripts/widgets/redux/farmplantpage","title":"Farmplantpage","description":"Renders a detailed UI page in the Plant Registry for a specific farm plant, showing unlocked knowledge (seasons, water, nutrients, description), plant stages, and oversized plant imagery.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/farmplantpage"},{"id":"game-scripts/components/farmplantstress","title":"Farmplantstress","description":"Tracks and evaluates stress conditions on farm plants to determine their final stress state based on environmental and gameplay factors.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farmplantstress"},{"id":"game-scripts/widgets/redux/farmplantsummarywidget","title":"Farmplantsummarywidget","description":"Renders a visual summary of a farm plant\'s properties including seed, product, seasons, water requirements, and nutrient effects in the UI.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/farmplantsummarywidget"},{"id":"game-scripts/components/farmplanttendable","title":"Farmplanttendable","description":"Controls whether a farm plant entity can be tended to, managing the `tendable_farmplant` tag and tend completion logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farmplanttendable"},{"id":"game-scripts/prefabs/flower","title":"Flower","description":"Represents a customizable plant entity that can transform into a rose under certain conditions and interacts with sanity, combat, and world state systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flower"},{"id":"game-scripts/prefabs/grass","title":"Grass","description":"Handles the lifecycle of grass patches including growth cycles, morphing into grass geckos, and interaction with world settings timers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/grass"},{"id":"game-scripts/prefabs/livingtree_root_planted","title":"Livingtree root planted","description":"A planted living tree seed that grows over two stages into a harvestable sapling, which then transforms into a livingtree_halloween upon growth completion.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/livingtree_root_planted"},{"id":"game-scripts/brains/lunarthrall_plant_vine_brain","title":"Lunarthrall Plant Vine Brain","description":"Controls the movement and\u884c\u4e3a logic for a Lunar Thrall gestalt entity tasked with moving toward and infesting a lunar plant target.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/lunarthrall_plant_vine_brain"},{"id":"game-scripts/prefabs/lureplant_bulb","title":"Lureplant Bulb","description":"A deployable item that spawns a Lureplant when placed in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lureplant_bulb"},{"id":"game-scripts/prefabs/mandrake_inactive","title":"Mandrake Inactive","description":"Represents an inactive mandrake plant prefab that becomes edible and triggers sleep effects when eaten raw or cooked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mandrake_inactive"},{"id":"game-scripts/prefabs/mandrake_planted","title":"Mandrake Planted","description":"A planted mandrake prefab that serves as the initial ground state before becoming active, and supports regrowth after being burned or replanted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mandrake_planted"},{"id":"game-scripts/prefabs/marblebean","title":"Marblebean","description":"A stackable inventory item that can be planted to spawn a marblebean sapling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marblebean"},{"id":"game-scripts/prefabs/marsh_bush","title":"Marsh Bush","description":"A harvestable, thorny plant prefab that yields twigs upon picking and triggers damage to non-resilient pickers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marsh_bush"},{"id":"game-scripts/prefabs/marsh_plant","title":"Marsh Plant","description":"Creates networked prefabs for marsh plants and pond algae, configuring visual state, burnable properties, and world propagation behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marsh_plant"},{"id":"game-scripts/prefabs/marsh_tree","title":"Marsh Tree","description":"Represents a harvestable tree prefab that yields loot upon chopping and transitions through states (normal, burnt, stump) with associated behaviors and event handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marsh_tree"},{"id":"game-scripts/prefabs/monkeytail","title":"Monkeytail","description":"A harvestable plant that produces reeds, regenerates over time, and supports being dug up with a shovel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/monkeytail"},{"id":"game-scripts/prefabs/moontree","title":"Moontree","description":"Manages the lifecycle, growth stages, burning, and harvesting of moon trees in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moontree"},{"id":"game-scripts/prefabs/oceantree","title":"Oceantree","description":"Manages the lifecycle, growth, and interaction logic for ocean trees, including chopping, burning, converting to stumps, and transforming into ocean pillars when enriched.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceantree"},{"id":"game-scripts/prefabs/palmconetree","title":"Palmconetree","description":"Defines the structure, growth stages, and behavior of the Palmcone Tree entity in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/palmconetree"},{"id":"game-scripts/prefabs/pinecone","title":"Pinecone","description":"Handles planting and deployment of tree saplings from seasonal pinecone items, including side effects on nearby Leif entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pinecone"},{"id":"game-scripts/components/plantable","title":"Plantable","description":"Initializes core growth parameters for plants, such as grow time and final product.","permalink":"/dst-api-webdocs/docs/game-scripts/components/plantable"},{"id":"game-scripts/prefabs/planted_tree","title":"Planted Tree","description":"Provides shared logic and factory functions for sapling prefabs that grow into trees after a timed period, with support for digging to harvest early.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/planted_tree"},{"id":"game-scripts/widgets/redux/plantpagewidget","title":"Plantpagewidget","description":"Serves as the base widget class for all plant registry pages, providing shared UI functionality like back navigation and input handling.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/plantpagewidget"},{"id":"game-scripts/components/plantregistryupdater","title":"Plantregistryupdater","description":"Manages plant and fertilizer discovery data for a player, syncing learned content across clients in multiplayer.","permalink":"/dst-api-webdocs/docs/game-scripts/components/plantregistryupdater"},{"id":"game-scripts/components/plantregrowth","title":"Plantregrowth","description":"Manages periodic regrowth of plants by tracking per-prefab timers and spawning nearby instances when growth conditions are met.","permalink":"/dst-api-webdocs/docs/game-scripts/components/plantregrowth"},{"id":"game-scripts/components/plantresearchable","title":"Plantresearchable","description":"Enables an entity to provide researchable plant information and supports unlocking plant stages for research purposes.","permalink":"/dst-api-webdocs/docs/game-scripts/components/plantresearchable"},{"id":"game-scripts/prefabs/quagmire_spiceshrub","title":"Quagmire Spiceshrub","description":"Defines the prefabs and initial setup for the Quagmire spiceshrub and its harvested components (sprig and ground spice) in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_spiceshrub"},{"id":"game-scripts/prefabs/quagmire_sugarwoodtree","title":"Quagmire Sugarwoodtree","description":"Defines the structure and assets for Quagmire sugarwood tree prefabs, including variants by size and tap state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_sugarwoodtree"},{"id":"game-scripts/prefabs/reeds","title":"Reeds","description":"A preconfigured plant prefab that provides cut reeds when harvested and serves as flammable fuel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/reeds"},{"id":"game-scripts/components/regrowthmanager","title":"Regrowthmanager","description":"Manages the scheduled regrowth of harvestable plants and structures after they are collected, using time-based timers and world state conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/regrowthmanager"},{"id":"game-scripts/prefabs/rock_avocado_bush","title":"Rock Avocado Bush","description":"A renewable plant prefab that grows through four distinct stages, yielding rock avocado fruits only at maturity before regrowing cycles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rock_avocado_bush"},{"id":"game-scripts/prefabs/rock_avocado_fruit","title":"Rock Avocado Fruit","description":"Manages the lifecycle and interactivity of rock avocado plant variants, including harvesting, cooking, planting, and growth.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rock_avocado_fruit"},{"id":"game-scripts/prefabs/sapling","title":"Sapling","description":"Manages the lifecycle, interaction, and transformation of sapling entities, including growth, harvesting, transplanting, and optional moon-phase conversion for seasonal variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sapling"},{"id":"game-scripts/prefabs/stalker_berry","title":"Stalker Berry","description":"A prefabricated plant entity that blooms over time, becomes harvestable, then wilts and respawns; used to spawn Wormlights when picked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stalker_berry"},{"id":"game-scripts/prefabs/stalker_bulb","title":"Stalker Bulb","description":"Manages the lifecycle of a stalker flower, including bloom phase, fading light effects, and regenerative picking behavior in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stalker_bulb"},{"id":"game-scripts/prefabs/stalker_ferns","title":"Stalker Ferns","description":"A world entity that starts as a wilted plant, blooms after a delay, becomes harvestable, and then decays after being left unharvested for a set time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stalker_ferns"},{"id":"game-scripts/prefabs/tree_rock_seed","title":"Tree Rock Seed","description":"A consumable item that, when deployed, grows into a tree_rock_sapling and replaces perishable spoilage with spoiled_food.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tree_rock_seed"},{"id":"game-scripts/widgets/redux/unknownplantpage","title":"Unknownplantpage","description":"Renders a UI page indicating that a plant in the Plant Registry is unknown (unresearched).","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/unknownplantpage"},{"id":"game-scripts/prefabs/waxed_plant_common","title":"Waxed Plant Common","description":"Provides utilities for creating waxed plant prefabs and converting existing plants into waxed variants with configurable appearance and behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waxed_plant_common"},{"id":"game-scripts/prefabs/weed_defs","title":"Weed Defs","description":"Defines configuration and behavior templates for weed plants, including growth stages, spread mechanics, and custom actions for forgetmelots, tillweed, firenettle, and ivy.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/weed_defs"},{"id":"game-scripts/prefabs/weed_plants","title":"Weed Plants","description":"A reusable prefab factory that creates customizable farmable weeds with growth stages, soil interaction, and magical growth mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/weed_plants"},{"id":"game-scripts/widgets/redux/weedplantpage","title":"Weedplantpage","description":"Renders the UI page for a specific weed plant type, displaying its growth stages, water/nutrient consumption, product, and effects with conditional visibility based on research progress.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/weedplantpage"},{"id":"game-scripts/components/witherable","title":"Witherable","description":"Manages cyclic withering and rejuvenation of plants based on temperature and weather conditions, and supports temporary protection periods.","permalink":"/dst-api-webdocs/docs/game-scripts/components/witherable"},{"id":"game-scripts/prefabs/wormlight_plant","title":"Wormlight Plant","description":"A harvestable light-emitting plant that regenerates after being picked and spawns a wormlight_lesser item.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormlight_plant"},{"id":"game-scripts/prefabs/wormwood_plant_fx","title":"Wormwood Plant Fx","description":"Renders a visual effect animation sequence associated with Wormwood\'s plant transformation, triggering growth or un-growth based on player proximity and state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormwood_plant_fx"}],"unlisted":false}}')}}]);